parameters.functionCode:
// Extraer comentarios
const posts = $json.data || [];
let results = [];

for (const post of posts) {
  const comments = post.comments?.data || [];
  for (const c of comments) {
    results.push({
      body: c.message,
      link: c.permalink_url,
      from: c.from?.name
    });
  }
}

return results.map(r => ({ json: r }));

