// mismo parser que ya tienes
let raw = $json?.content?.parts?.[0]?.text || "";
let clean = raw.replace(/```json|```/g, '').trim();
let match = clean.match(/\{[\s\S]*\}/);
let parsed = JSON.parse(match[0]);
parsed.confidence = Number(parsed.confidence) || 0;
return [{ json: { ...$json, ...parsed } }];
